using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Agents.AI;
using Microsoft.Agents.AI.ChatCompletion;

var builder = Host.CreateApplicationBuilder(args);

var apiKey = builder.Configuration["AI:ApiKey"]
    ?? Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the API key via 'AI:ApiKey' config or OPENAI_API_KEY env var.");

var modelId = builder.Configuration["AI:ModelId"] ?? "gpt-4o-mini-2024-07-18";

builder.Services.AddChatClient(b => b
    .UseOpenAIChatClient(modelId, apiKey));

builder.Services.AddSingleton<Notebook>();
builder.Services.AddSingleton<WebSearchTool>();

using var host = builder.Build();

var chatClient = host.Services.GetRequiredService<IChatClient>();
var notebook   = host.Services.GetRequiredService<Notebook>();
var webSearch   = host.Services.GetRequiredService<WebSearchTool>();

var tools = new AIFunctionFactory[]{ }; // placeholder — real tools below
var aiTools = new List<AITool>
{
    AIFunctionFactory.Create(webSearch.SearchAsync),
    AIFunctionFactory.Create(notebook.AddNote),
    AIFunctionFactory.Create(notebook.GetNotes),
};

var agent = new ChatClientAgent(
    chatClient,
    "ResearchAgent",
    "You are a research assistant. "
    + "When given a topic, use the web_search tool to find relevant information. "
    + "Take notes on key findings with the add_note tool. "
    + "Search multiple queries to get a comprehensive view. "
    + "After gathering enough information, retrieve your notes with get_notes "
    + "and produce a well-structured summary with citations.");

Console.WriteLine("╔══════════════════════════════════╗");
Console.WriteLine("║   Research Agent  (type 'quit')  ║");
Console.WriteLine("╚══════════════════════════════════╝");
Console.WriteLine();

while (true)
{
    Console.ForegroundColor = ConsoleColor.Cyan;
    Console.Write("Research topic> ");
    Console.ResetColor();

    var topic = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(topic) || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
        break;

    notebook.Clear();

    var history = new List<ChatMessage>
    {
        new(ChatRole.User, $"Research the following topic and provide a summary: {topic}")
    };

    var options = new AgentInvokeOptions
    {
        MaximumIterations = 10,
    };

    var chatOptions = new ChatOptions
    {
        Temperature = 0f,
        MaxOutputTokens = 2048,
        Tools = aiTools,
    };

    Console.ForegroundColor = ConsoleColor.DarkGray;
    Console.WriteLine($"\n⏳ Researching \"{topic}\"...\n");
    Console.ResetColor();

    try
    {
        await foreach (var message in agent.InvokeStreamingAsync(
            history, chatOptions, options))
        {
            if (message.Role == ChatRole.Assistant && !string.IsNullOrWhiteSpace(message.Text))
            {
                Console.Write(message.Text);
            }
        }

        Console.WriteLine("\n");
    }
    catch (Exception ex)
    {
        Console.ForegroundColor = ConsoleColor.Red;
        Console.WriteLine($"\n❌ Error: {ex.Message}\n");
        Console.ResetColor();
    }
}

Console.WriteLine("Goodbye!");

// ── Tools ───────────────────────────────────────────────────────────────────

/// <summary>Simulated web search tool that returns mock results for demonstration.</summary>
public sealed class WebSearchTool
{
    [Description("Searches the web for the given query and returns a list of results with titles, snippets, and URLs.")]
    public Task<string> SearchAsync(
        [Description("The search query string")] string query)
    {
        // In production, replace with a real search API (Bing, Google, Tavily, etc.)
        var results = GenerateMockResults(query);
        return Task.FromResult(JsonSerializer.Serialize(results, new JsonSerializerOptions
        {
            WriteIndented = true
        }));
    }

    private static List<SearchResult> GenerateMockResults(string query)
    {
        var q = query.ToLowerInvariant();
        return
        [
            new($"Overview of {query}", 
                $"A comprehensive overview covering the key aspects of {query}. "
                + "Recent studies show significant developments in this area with "
                + "multiple breakthroughs reported in 2025-2026.",
                $"https://example.com/overview/{Uri.EscapeDataString(q)}"),

            new($"{query} – Recent Advances",
                $"Researchers have made notable progress in {query}. "
                + "New methodologies have improved efficiency by up to 40% "
                + "compared to previous approaches.",
                $"https://example.com/advances/{Uri.EscapeDataString(q)}"),

            new($"Practical Applications of {query}",
                $"Industry adoption of {query} has accelerated. "
                + "Key sectors include healthcare, finance, and manufacturing, "
                + "with projected market growth of 25% annually through 2028.",
                $"https://example.com/applications/{Uri.EscapeDataString(q)}"),
        ];
    }

    private record SearchResult(string Title, string Snippet, string Url);
}

/// <summary>Note-taking tool that stores research findings in memory.</summary>
public sealed class Notebook
{
    private readonly List<string> _notes = [];

    [Description("Adds a research note. Use this to record key findings, facts, or insights discovered during research.")]
    public string AddNote(
        [Description("The note content to save")] string note)
    {
        _notes.Add(note);
        return $"Note #{_notes.Count} saved.";
    }

    [Description("Retrieves all saved research notes as a numbered list.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes recorded yet.";

        return string.Join("\n", _notes.Select((n, i) => $"{i + 1}. {n}"));
    }

    public void Clear() => _notes.Clear();
}

